//! Live containment of moonshine.
//!
//! An admitted `Allow` must reach the *real* moonshine and return its real
//! output - never a fabrication (faking an Allow would be a silent quality
//! degrade, which is forbidden). moonshine has no linkable executor and no
//! shell-exec library entry, but its CLI does: `moonshine -c "<cmd>"` runs a
//! single shell command non-interactively and exits. So the gateway shells out
//! to it, optionally wrapped in a monster-guard lease/sandbox the way
//! monster-swarm launches its nodes (`monster-guard run ... -- <node> <args>`).
//!
//! The shadow path never touches this. Containment is only for the good guy.

use std::process::Command;

use crate::Gateway;

/// Forwards admitted commands to a contained moonshine process.
pub struct ProcessGateway {
    /// Path to the moonshine binary (`$MOONSHINE_BIN`, else `moonshine` on PATH).
    pub moonshine_bin: String,
    /// Wrap the child in a monster-guard lease + sandbox when true.
    pub use_guard: bool,
    /// Sandbox capability set passed to `monster-guard run --caps`.
    pub caps: String,
    /// Lease duration handed to `monster-guard run --lease` (seconds).
    pub lease_secs: u64,
}

impl Default for ProcessGateway {
    fn default() -> Self {
        ProcessGateway {
            moonshine_bin: "moonshine".to_string(),
            use_guard: false,
            // `exec` is required: monster-guard's sandbox emits (deny process-fork)
            // unless `exec` is present, which would block any non-builtin command.
            caps: "fs,net,exec".to_string(),
            lease_secs: 30,
        }
    }
}

impl ProcessGateway {
    /// Build from the environment. `MOONSHINE_BIN` overrides the binary;
    /// `MONSTER_BADCHILD_GUARD=1` enables the monster-guard lease wrapper.
    pub fn from_env() -> Self {
        let mut g = ProcessGateway::default();
        if let Ok(bin) = std::env::var("MOONSHINE_BIN") {
            if !bin.is_empty() {
                g.moonshine_bin = bin;
            }
        }
        g.use_guard = std::env::var("MONSTER_BADCHILD_GUARD")
            .map(|v| v == "1" || v.eq_ignore_ascii_case("true"))
            .unwrap_or(false);
        if let Ok(lease) = std::env::var("MONSTER_BADCHILD_LEASE_SECS") {
            if let Ok(secs) = lease.parse() {
                g.lease_secs = secs;
            }
        }
        g
    }

    fn run(&self, command: &str) -> std::io::Result<std::process::Output> {
        if self.use_guard {
            // `monster-guard run` is not self-admitting: it refuses any plugin
            // name without an existing delegated grant. Mint/refresh it first,
            // exactly as monster-swarm pairs delegate() with run_detached().
            let _ = Command::new(monster_swarm::guard::guard_bin())
                .args([
                    "delegate",
                    "badchild-session",
                    &self.caps,
                    "--ttl",
                    &(self.lease_secs + 5).to_string(),
                ])
                .status();
            // monster-guard run --name <n> --caps <c> --lease <s> -- moonshine -c <cmd>
            Command::new(monster_swarm::guard::guard_bin())
                .arg("run")
                .args([
                    "--name",
                    "badchild-session",
                    "--caps",
                    &self.caps,
                    "--lease",
                    &self.lease_secs.to_string(),
                ])
                .arg("--")
                .arg(&self.moonshine_bin)
                .args(["-c", command])
                .output()
        } else {
            Command::new(&self.moonshine_bin).args(["-c", command]).output()
        }
    }
}

impl Gateway for ProcessGateway {
    fn forward(&self, command: &str) -> String {
        match self.run(command) {
            Ok(out) => {
                let mut body = String::from_utf8_lossy(&out.stdout).to_string();
                let err = String::from_utf8_lossy(&out.stderr);
                if !err.trim().is_empty() {
                    body.push_str(&err);
                }
                body
            }
            // The Allow path surfaces a real operational failure honestly rather
            // than fabricating success. Allow only ever serves authorized,
            // unobserved callers, so this never leaks to an adversary.
            Err(e) => format!("gateway: could not reach contained moonshine: {e}\n"),
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn missing_binary_surfaces_an_honest_error_not_a_fake() {
        let g = ProcessGateway {
            moonshine_bin: "definitely-not-a-real-binary-xyz".to_string(),
            use_guard: false,
            caps: "fs".to_string(),
            lease_secs: 1,
        };
        let out = g.forward("pwd");
        assert!(out.contains("gateway:"), "must report the failure, not fake output");
    }

    #[test]
    fn from_env_defaults_are_sane() {
        let g = ProcessGateway::from_env();
        assert!(!g.moonshine_bin.is_empty());
    }
}
